            ds_commInfo.removeAll();
            ds_commInfo.reform();

            //검색조건 - 오더번호
            dma_cndOdrNo.setEmptyValue();

            //팝업 hidden values 세팅
            scwin.f_setHidValues(2);

            //오더정보 세팅
