/**
 * method
 * @name f_tmlEdiIfno
 * @description 터미널 EDI 정보입력 화면 팝업
 */
scwin.f_tmlEdiIfno = async function () {
    let odrNo = ds_odrInfo.getCellData(0, "odrNo");
    if ($c.gus.cfIsNull(odrNo)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_049, new Array("오더정보"));
        return false;
    }

    let arrParam = new Array(10);
    arrParam[0] = odrNo; //오더번호
    let param = {
        "odrNo": odrNo
    };
    param.arrParam = arrParam;
    let options = {
        id: "sd_402_01_18p_popup",
        popupName: "터미널 EDI 정보입력",
        modal: true,
        type: "browserPopup",  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        width: 850,
        height: 355,
    };

    await $c.win.openPopup("/ui/ds/sd/odrmgnt/odrreg/sd_402_01_18p.xml", options, param);
};

