/**
 * event
 * @name acb_odrKndCd_onviewchange
 * @description
 */
scwin.acb_odrKndCd_onviewchange = function (info) {
    scwin.odrKndCd = acb_odrKndCd.getValue();		//오더종류코드
    let idx = acb_odrKndCd.getSelectedRow();
    scwin.impExpClsCd = ds_odrKndCd.getCellData(idx, "fltrCd2");//수출입구분코드
    if (scwin.impExpClsCd == "null") {
        scwin.impExpClsCd = ""; //TS셔틀컨테이너가 아닌 경우
    }
    //scwin.odrKndCd은 DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR = "C2";로 고정된다.
    if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EXP_GNRL_CNTR_ODR
        || scwin.odrKndCd == DsConstants.ODR_KND_CD_EMPTY_POSITION_ODR) {
        if (ed_sellLodeptCd.getValue().substring(0, 2) == "6A" || ed_sellLodeptCd.getValue() == null || ed_sellLodeptCd.getValue() == "") {
            $c.gus.cfEnableObj(ed_alloccarPicNm1, false);	//ed_alloccarPicNm1
            $c.gus.cfEnableObj(ed_alloccarPicNm2, false);	//ed_alloccarPicNm2
            $c.gus.cfEnableObj(ed_alloccarPicNm3, false);	//ed_alloccarPicNm3
            $c.gus.cfEnableObj(ed_alloccarPicNm4, false);	//ed_alloccarPicNm4
            $c.gus.cfEnableObj(ed_alloccarPicNm5, false);	//ed_alloccarPicNm5
        } else {
            $c.gus.cfEnableObj(ed_alloccarPicNm1, true);	//ed_alloccarPicNm1
            $c.gus.cfEnableObj(ed_alloccarPicNm2, true);	//ed_alloccarPicNm2
            $c.gus.cfEnableObj(ed_alloccarPicNm3, true);	//ed_alloccarPicNm3
            $c.gus.cfEnableObj(ed_alloccarPicNm4, true);	//ed_alloccarPicNm4
            $c.gus.cfEnableObj(ed_alloccarPicNm5, true);	//ed_alloccarPicNm5
        }
    } else {
        $c.gus.cfEnableObj(ed_alloccarPicNm1, true);	//ed_alloccarPicNm1
        $c.gus.cfEnableObj(ed_alloccarPicNm2, true);	//ed_alloccarPicNm2
        $c.gus.cfEnableObj(ed_alloccarPicNm3, true);	//ed_alloccarPicNm3
        $c.gus.cfEnableObj(ed_alloccarPicNm4, true);	//ed_alloccarPicNm4
        $c.gus.cfEnableObj(ed_alloccarPicNm5, true);	//ed_alloccarPicNm5
    }
};

/**
 * event
 * @name lc_ctrtNo_onviewchange
 * @description
 */
scwin.lc_ctrtNo_onviewchange = async function (info) {
    if (ds_ctrtNo.getRowCount() > 0 && scwin.mgntTrgtClntYn != "1") {
        let idx = lc_ctrtNo.getSelectedIndex();
        scwin.mgntTrgtClntYn = ds_ctrtNo.getCellData(idx, "mgntTrgtClntYn");
        if (scwin.mgntTrgtClntYn == "1") {
            if (scwin.statusFlag == "C") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["본 계약거래처", "관리대상이므로 오더등록"]);   //"@은(는) @할 수 없습니다.

                await scwin.f_set("INIT", "INIT2"); //초기화
            } else {
                await $c.gus.cfAlertMsg(MSG_SD_WRN_006, ["본 계약거래처", "관리대상"]);   //"@은(는) @입니다.

                $c.gus.cfDisableKeyData();
                $c.gus.cfDisableAllBtn();
                $c.gus.cfDisableObjects([btn_confirmOdr1, btn_confirmOdr2, btn_updateCntrInfo, btn_chgCntrNoInfo, btn_updateRepWrkInfo, btn_dcSc, btn_unitySelling, btn_copyOdr]);
                $c.gus.cfEnableBtnOnly([btn_create, btn_create1]);
            }
        } else {
            if (scwin.retrieveYn == "N") {
                await scwin.f_retrieveClntList();
            }
        }
    }
};

